    // 3. Set up initial relationship (A -> B)
    nodeA->addOneObserver(nodeB);

    // 4. Notify target and verify relationship works
    nodeA->valueChanged();

    // Verify B was notified
    if (nodeB->getCallCount() != 1) {
        return false;
