Looking at the code fragments provided, I can see that the `reaction` library has a naming system for reactive nodes. Here's the implementation of the `test_named_reactions` function:

```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test naming reactive nodes and retrieving names
 *
 * @param valueA Initial value for varA
 * @param valueB Initial value for varB
 * @return std::string Combined string of retrieved names
 */
std::string test_named_reactions(int valueA, int valueB) {
    // 1. Create reactive variables with names
    auto varA = reaction::Var<int>::make(valueA, "varA");
    auto varB = reaction::Var<int>::make(valueB, "varB");

    // 2. Create calculations with names
    auto calcSum = reaction::Calc<int>::make(
        [varA, varB]() { return varA->get() + varB->get(); },
        "sumCalculation"
    );

    auto calcProduct = reaction::Calc<int>::make(
        [varA, varB]() { return varA->get() * varB->get(); },
        "productCalculation"
    );

    // 3. Create action with name
    std::string actionResult;
    auto testAction = reaction::Action::make(
        [varA, &actionResult]() {
            int current = varA->get();
            varA->set(current + 1);
            actionResult = "Incremented varA from " + std::to_string(current);
        },
        "testAction"
    );

    // 4. Retrieve names
    std::string varAName = varA->getName().value_or("unnamed_varA");
    std::string varBName = varB->getName().value_or("unnamed_varB");
    std::string sumCalcName = calcSum->getName().value_or("unnamed_sum");
    std::string productCalcName = calcProduct->getName().value_or("unnamed_product");
    std::string actionName = testAction->getName().value_or("unnamed_action");

    // 5. Return combined names string
    return varAName + "," + varBName + "," + sumCalcName + "," + 
           productCalcName + "," + actionName;
}

}  // namespace test_reaction
```

