```cpp
#pragma once

#include <reaction/reaction.h>
#include <tuple>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test filter trigger with conditional recomputation
 *
 * @param initialValue Initial sensor value
 * @param firstUpdate First update (expected to be within threshold)
 * @param secondUpdate Second update (expected to exceed threshold)
 * @param diffThreshold Minimum delta to trigger recomputation
 * @param levelThreshold Threshold to categorize HIGH vs NORMAL
 * @return std::tuple<std::string, int, int>
 *         {final status string, recompute count after first update, recompute count after second update}
 */
std::tuple<std::string, int, int> test_filter_trigger(double initialValue,
                                                      double firstUpdate,
                                                      double secondUpdate,
                                                      double diffThreshold,
                                                      double levelThreshold) {
    // 1. Create reactive variable
    reaction::Var<double> sensor(initialValue);

    // 2. Create variables to track recomputation count and last processed value
    int recomputeCount = 0;
    double lastProcessedValue = initialValue;

    // 3. Create filter-triggered calculation
    auto statusCalc = reaction::Computed<std::string>([&]() {
        recomputeCount++;
        double currentValue = sensor.get();
        lastProcessedValue = currentValue;

        if (currentValue >= levelThreshold) {
            return std::string("HIGH");
        } else {
            return std::string("NORMAL");
        }
    });

    // 4. Apply filter
    auto filteredSensor = sensor.filter([diffThreshold, &lastProcessedValue](double newValue) {
        return std::abs(newValue - lastProcessedValue) >= diffThreshold;
    });

    // Connect filtered sensor to status calculation
    filteredSensor.onChange([&statusCalc]() {
        // Force recomputation when filter passes
        statusCalc.touch();
    });

    // Initialize status
    std::string initialStatus = statusCalc.get();
    int initialRecomputeCount = recomputeCount;

    // 5. Update sensor with first value
    sensor.set(firstUpdate);

    // 6. Record recompute count after first update
    int firstUpdateRecomputeCount = recomputeCount;

    // 7. Update sensor with second value
    sensor.set(secondUpdate);

    // 8. Record recompute count after second update
    int secondUpdateRecomputeCount = recomputeCount;

    // 9. Get final status
    std::string finalStatus = statusCalc.get();

    // 10. Return final status and counts
    return {finalStatus, firstUpdateRecomputeCount - initialRecomputeCount, 
            secondUpdateRecomputeCount - firstUpdateRecomputeCount};
}

}  // namespace test_reaction
```

This implementation uses the `reaction` library to:

1. Create a reactive sensor variable with the initial value
2. Track recomputation count and last processed value
3. Create a filter-triggered calculation that categorizes values as "HIGH" or "NORMAL"
4. Apply a filter that only triggers recomputation when the change exceeds the threshold
5-8. Update the sensor and track recomputation counts after each update
9-10. Return the final status and the incremental recomputation counts

The filter ensures that the status calculation only recomputes when the sensor value changes by more than the specified threshold, demonstrating conditional recomputation behavior.

